function withUniqueRecvPrototypeComps(recvArchetypes){
  const seen = new Set();
  return recvArchetypes.map((arch)=>{
    const picked = [];

    const tryPick = (name)=>{
      if (!name || seen.has(name) || picked.includes(name)) return;
      picked.push(name);
      seen.add(name);
    };

    (arch.examples || []).forEach(tryPick);
    (RECV_PROTOTYPE_FALLBACKS[arch.key] || []).forEach((name)=>{
      if (picked.length < 3) tryPick(name);
    });
    GLOBAL_PROTOTYPE_POOL.forEach((name)=>{
      if (picked.length < 3) tryPick(name);
    });

    return {
      ...arch,
      examples: picked.slice(0,3),
    };
  });
}

